const tunnels = $input.first().json.tunnels ?? [];
const https = tunnels.find(t => t.proto === 'https') ?? tunnels[0];
if (!https) throw new Error('Heartbeat: no ngrok tunnel found. Is the ngrok sidecar running?');
const url = https.public_url;
console.log('[Heartbeat] ngrok URL:', url);
return [{ json: { url } }];

// Merge both webhook update results and pass one item downstream
const wa = (() => { try { return $('Update WhatsApp Webhook').first()?.json; } catch(e) { return { error: e.message }; } })();
const tg = (() => { try { return $('Update Telegram Webhook').first()?.json; } catch(e) { return { error: e.message }; } })();
console.log('[Heartbeat] WA update:', JSON.stringify(wa));
console.log('[Heartbeat] TG update:', JSON.stringify(tg));
return [{ json: { webhook_wa: wa, webhook_tg: tg, ngrok_url: $('Extract URL').first().json.url } }];

// Find the Multi-Channel Router workflow ID on the brain
// This is the workflow that holds the live webhook registrations
const data = $input.first().json;
const workflows = data.data ?? [];
const RECEPTIONIST_NAMES = [
  '[UNIFIED] Multi-Channel Router',
  'YAOC2 Telegram Receptionist',
  'YAOC2 WhatsApp Receptionist'
];
const targets = workflows.filter(w =>
  RECEPTIONIST_NAMES.some(name => w.name?.includes(name) || name.includes(w.name))
);
if (targets.length === 0) {
  // Non-fatal: brain may not have these workflow names, log and skip
  console.log('[Heartbeat] No receptionist workflows found on brain to bounce. Skipping.');
  return [{ json: { bounce_ids: [], skipped: true } }];
}
console.log('[Heartbeat] Bouncing workflows:', targets.map(w => w.name + ' (' + w.id + ')').join(', '));
return [{ json: { bounce_ids: targets.map(w => w.id), skipped: false } }];

// Deactivate then reactivate each receptionist workflow on the brain
// This forces n8n to rebind webhook UUIDs in its in-memory registry
const brainUrl = $env.BRAIN_N8N_URL ?? 'http://192.168.101.168:5678';
const apiKey = $env.BRAIN_N8N_API_KEY;
if (!apiKey) throw new Error('Heartbeat: BRAIN_N8N_API_KEY not set — cannot bounce workflows');
const ids = $input.first().json.bounce_ids ?? [];
const results = [];
for (const id of ids) {
  try {
    // Deactivate
    await helpers.httpRequest({
      method: 'PATCH',
      url: `${brainUrl}/api/v1/workflows/${id}`,
      headers: { 'X-N8N-API-KEY': apiKey, 'Content-Type': 'application/json' },
      body: JSON.stringify({ active: false })
    });
    // Brief pause to let n8n flush the registry
    await new Promise(r => setTimeout(r, 800));
    // Reactivate
    await helpers.httpRequest({
      method: 'PATCH',
      url: `${brainUrl}/api/v1/workflows/${id}`,
      headers: { 'X-N8N-API-KEY': apiKey, 'Content-Type': 'application/json' },
      body: JSON.stringify({ active: true })
    });
    results.push({ id, bounced: true });
    console.log('[Heartbeat] Bounced workflow:', id);
  } catch(e) {
    // Non-fatal: log but don't break the heartbeat
    results.push({ id, bounced: false, error: e.message });
    console.warn('[Heartbeat] Failed to bounce workflow ' + id + ':', e.message);
  }
}
return [{ json: { bounce_results: results, completed_at: new Date().toISOString() } }];
